export const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

// --- Schema Adapters ---

// Helper to parse potential JSON content for rich media within the 'content' column
export const parseMessageContent = (msg: any): Message => {
  if (!msg) return msg;
  try {
    // Check if content is a JSON string containing our rich media keys
    if (typeof msg.content === 'string' && msg.content.trim().startsWith('{')) {
       const parsed = JSON.parse(msg.content);
       // Verify it has expected structure
       if (parsed.type) {
           return {
             ...msg,
             content: parsed.content || parsed.text || '',
             type: parsed.type || 'text',
             media_url: parsed.media_url
           };
       }
    }
  } catch (e) {
    // Fallback for plain text, do nothing
  }
  // Ensure default type is text if parsing failed or wasn't applicable
  return { ...msg, type: msg.type || 'text' };
};

// --- API Implementation ---

export const api = {
  // --- Auth ---
  signUpWithEmail: async (email: string, pass: string, fullName: string): Promise<void> => {
    const { error } = await supabase.auth.signUp({
      email,
      password: pass,
      options: { data: { full_name: fullName } }
    });
    if (error) throw error;
  },

  signInWithPassword: async (email: string, pass: string): Promise<CurrentUser> => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password: pass });
    if (error) throw error;

    // Fetch or construct profile
    const profile = await api.getUserProfile(data.user.id).catch(() => null);

    if (!profile) {
        // Fallback using auth metadata if profile row is missing
        return {
            id: data.user.id,
            username: data.user.user_metadata?.full_name?.replace(/\s+/g, '_').toLowerCase() || email.split('@')[0],
            avatar_url: `https://api.dicebear.com/7.x/avataaars/svg?seed=${data.user.id}`,
            full_name: data.user.user_metadata?.full_name
        };
    }
    return profile;
  },

  resetPassword: async (email: string): Promise<void> => {
    const { error } = await supabase.auth.resetPasswordForEmail(email, { redirectTo: window.location.origin + '/#/login' });
    if (error) throw error;
  },

  signOut: async (): Promise<void> => {
    await supabase.auth.signOut();
    window.location.href = '/';
  },

  getCurrentUser: async (): Promise<CurrentUser> => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error('No user logged in');

    const { data } = await supabase.from('profiles').select('*').eq('id', user.id).maybeSingle();

    // Fetch real-time counts directly from follows table
    const { count: followersCount } = await supabase
        .from('follows')
        .select('*', { count: 'exact', head: true })
        .eq('following_id', user.id);

    const { count: followingCount } = await supabase
        .from('follows')
        .select('*', { count: 'exact', head: true })
        .eq('follower_id', user.id);

    // Return merged data or fallback from auth metadata
    return {
        id: user.id,
        username: data?.username || user.user_metadata?.full_name?.replace(/\s+/g, '_').toLowerCase() || 'user',
        avatar_url: data?.avatar_url || user.user_metadata?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.id}`,
        full_name: data?.full_name || user.user_metadata?.full_name,
        bio: data?.bio,
        followers_count: followersCount || 0,
        following_count: followingCount || 0
    };
  },

  updateCurrentUser: async (updates: Partial<CurrentUser>): Promise<CurrentUser> => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error('No user');

    // Whitelist allowed fields to prevent errors with virtual properties
    const safeUpdates: any = {};
    if (updates.full_name !== undefined) safeUpdates.full_name = updates.full_name;
    if (updates.bio !== undefined) safeUpdates.bio = updates.bio;
    if (updates.avatar_url !== undefined) safeUpdates.avatar_url = updates.avatar_url;

    // Use maybeSingle to avoid error if row doesn't exist
    const { data, error } = await supabase.from('profiles').update(safeUpdates).eq('id', user.id).select().maybeSingle();

    if (error) throw error;

    if (!data) {
        // If profile row missing, create it now
        const username = user.user_metadata?.full_name?.replace(/\s+/g, '_').toLowerCase() || user.email?.split('@')[0] || `user_${user.id.slice(0,8)}`;
        const { error: insertError } = await supabase.from('profiles').insert({
            id: user.id,
            username: username,
            avatar_url: safeUpdates.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.id}`,
            full_name: safeUpdates.full_name || user.user_metadata?.full_name || '',
            bio: safeUpdates.bio || '',
            updated_at: new Date().toISOString()
        });
        if (insertError) throw insertError;
    }

    // Re-fetch to get correct counts and virtuals
    return await api.getUserProfile(user.id);
  },

  // --- Profiles ---
  getUserProfile: async (userId: string): Promise<Profile> => {
    const { data: { user } } = await supabase.auth.getUser();
    const { data, error } = await supabase.from('profiles').select('*').eq('id', userId).single();
    if (error) throw error;

    // Fetch real-time counts from the source of truth
    const { count: followersCount } = await supabase
        .from('follows')
        .select('*', { count: 'exact', head: true })
        .eq('following_id', userId);

    const { count: followingCount } = await supabase
        .from('follows')
        .select('*', { count: 'exact', head: true })
        .eq('follower_id', userId);

    let isFollowing = false;
    if (user && user.id !== userId) {
         const { data: follow } = await supabase.from('follows').select('*').match({ follower_id: user.id, following_id: userId }).single();
         isFollowing = !!follow;
    }

    return { 
        ...data, 
        is_following: isFollowing,
        followers_count: followersCount || 0,
        following_count: followingCount || 0 
    };
  },

  getAllProfiles: async (): Promise<Profile[]> => {
    const { data } = await supabase.from('profiles').select('*').limit(50);
    return data || [];
  },

  // --- Feed & Posts ---
  getFeed: async (): Promise<Post[]> => {
    const { data: { user } } = await supabase.auth.getUser();

    // Fetch posts with profiles and real-time counts from related tables
    const { data, error } = await supabase
      .from('posts')
      .select(`
        *,
        profiles:user_id(*),
        likes(count),
        comments(count)
      `)
      .order('created_at', { ascending: false });

    if (error) throw error;

    // Batch fetch 'has_liked' status for the current user
    let likedPostIds = new Set<string>();
    if (user) {
        const { data: likesData } = await supabase
            .from('likes')
            .select('post_id')
            .eq('user_id', user.id);
        likesData?.forEach((l: any) => likedPostIds.add(l.post_id));
    }

    return data.map((p: any) => ({
         ...p,
         profiles: p.profiles,
         // Use the count from relations, fallback to 0
         likes_count: p.likes?.[0]?.count || 0,
         comments_count: p.comments?.[0]?.count || 0,
         has_liked: likedPostIds.has(p.id)
    }));
  },

  getPost: async (postId: string): Promise<Post | null> => {
      const { data: { user } } = await supabase.auth.getUser();

      const { data, error } = await supabase
        .from('posts')
        .select(`
          *,
          profiles:user_id(*),
          likes(count),
          comments(count)
        `)
        .eq('id', postId)
        .single();

      if (error) return null;

      let hasLiked = false;
      if (user) {
         const { data: likeData } = await supabase
           .from('likes')
           .select('id')
           .match({ post_id: postId, user_id: user.id })
           .single();
         hasLiked = !!likeData;
      }

      return {
          ...data,
          profiles: data.profiles,
          likes_count: data.likes?.[0]?.count || 0,
          comments_count: data.comments?.[0]?.count || 0,
          has_liked: hasLiked
      };
  },

  getUserPosts: async (userId: string): Promise<Post[]> => {
      const { data } = await supabase.from('posts').select('*').eq('user_id', userId).order('created_at', { ascending: false });
      return data || [];
  },

  createPost: async (imageUrl: string, caption: string, userId: string): Promise<void> => {
    await supabase.from('posts').insert({ user_id: userId, image_url: imageUrl, caption });
  },

  deletePost: async (postId: string): Promise<void> => {
    await supabase.from('posts').delete().eq('id', postId);
  },

  likePost: async (postId: string, userId: string, ownerId: string): Promise<void> => {
    // Check if already liked
    const { data } = await supabase.from('likes').select('id').match({ user_id: userId, post_id: postId }).single();

    if (data) {
        await supabase.from('likes').delete().eq('id', data.id);
    } else {
        await supabase.from('likes').insert({ user_id: userId, post_id: postId });
    }
  },

  // --- Comments ---
  getComments: async (postId: string): Promise<Comment[]> => {
    const { data } = await supabase.from('comments').select('*, profile:user_id(*)').eq('post_id', postId).order('created_at', { ascending: true });
    return data || [];
  },

  addComment: async (postId: string, userId: string, content: string): Promise<Comment> => {
    const { data, error } = await supabase.from('comments').insert({ post_id: postId, user_id: userId, content }).select('*, profile:user_id(*)').single();
    if (error) throw error;
    return data;
  },

  deleteComment: async (commentId: string): Promise<void> => {
      await supabase.from('comments').delete().eq('id', commentId);
  },

  // --- Interactions ---
  followUser: async (followerId: string, targetId: string): Promise<void> => {
      await supabase.from('follows').insert({ follower_id: followerId, following_id: targetId });
  },

  unfollowUser: async (followerId: string, targetId: string): Promise<void> => {
      await supabase.from('follows').delete().match({ follower_id: followerId, following_id: targetId });
  },

  // --- Messaging ---
  getMessages: async (friendId: string): Promise<Message[]> => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return [];

      const { data, error } = await supabase.from('messages').select('*')
         .or(`and(sender_id.eq.${user.id},receiver_id.eq.${friendId}),and(sender_id.eq.${friendId},receiver_id.eq.${user.id})`)
         .order('created_at', { ascending: true });

      if (error) throw error;

      // Parse JSON content if necessary
      return (data || []).map(parseMessageContent);
  },

  getLastMessage: async (friendId: string): Promise<Message | null> => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return null;

      const { data, error } = await supabase.from('messages').select('*')
         .or(`and(sender_id.eq.${user.id},receiver_id.eq.${friendId}),and(sender_id.eq.${friendId},receiver_id.eq.${user.id})`)
         .order('created_at', { ascending: false })
         .limit(1)
         .single();

      if (error || !data) return null;
      return parseMessageContent(data);
  },

  sendMessage: async (senderId: string, receiverId: string, content: string, type: 'text' | 'image' | 'audio' = 'text', mediaUrl?: string): Promise<Message> => {
      // Pack rich data into 'content' if it's not plain text, to support restricted schema
      let finalContent = content;
      if (type !== 'text' || mediaUrl) {
          finalContent = JSON.stringify({
              content: content,
              type: type,
              media_url: mediaUrl
          });
      }

      const { data, error } = await supabase.from('messages').insert({ 
          sender_id: senderId, 
          receiver_id: receiverId, 
          content: finalContent 
      }).select().single();

      if (error) throw error;
      return parseMessageContent(data);
  },

  // --- Storage ---
  uploadFile: async (file: File): Promise<string> => {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}_${Math.random().toString(36).substr(2, 9)}.${fileExt}`;
      const { error } = await supabase.storage.from('images').upload(fileName, file);
      if (error) throw error;

      const { data } = supabase.storage.from('images').getPublicUrl(fileName);
      return data.publicUrl;
  },

  // --- Notifications ---
  getNotifications: async (): Promise<Notification[]> => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return [];

      const { data } = await supabase.from('notifications').select('*, sender_profile:sender_id(*)').eq('user_id', user.id).order('created_at', { ascending: false });
      return data || [];
  },

  markNotificationRead: async (notifId: string) => {
      await supabase.from('notifications').update({ is_read: true }).eq('id', notifId);
  }
};

import React, { useEffect, useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { api, supabase, parseMessageContent } from '../../../services/supabaseClient';
import { Message, CurrentUser } from '../../../types';
import { motion } from 'framer-motion';
import { theme, commonStyles } from '../../../Theme';
import { Lightbox } from '../../Core/Lightbox';
import { ChatHeader, ChatInput, MessageBubble } from './ChatPrimitives';

interface DirectChatProps {
    friendId: string;
}

export const DirectChat: React.FC<DirectChatProps> = ({ friendId }) => {
    const navigate = useNavigate();
    const [messages, setMessages] = useState<Message[]>([]);
    const [currentUser, setCurrentUser] = useState<CurrentUser | null>(null);
    const [friendProfile, setFriendProfile] = useState<any>(null);
    const [lightboxSrc, setLightboxSrc] = useState<string | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        setTimeout(scrollToBottom, 100);
    }, [messages.length]);

    useEffect(() => {
        let ignore = false;
        let channel: any = null;

        const init = async () => {
            const user = await api.getCurrentUser();
            if (ignore) return;
            setCurrentUser(user);

            // Fetch Messages
            const msgs = await api.getMessages(friendId);
            if (ignore) return;
            setMessages(msgs);

            const friend = (await api.getAllProfiles()).find(p => p.id === friendId);
            if (ignore) return;
            setFriendProfile(friend);

            // Subscribe to DM updates
            channel = supabase.channel(`dm:${user.id}:${friendId}`)
               .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'messages' }, payload => {
                   const msg = parseMessageContent(payload.new);

                   // REALTIME: Only add messages from the OTHER user. Own messages are handled optimistically.
                   if (msg.sender_id === friendId && msg.receiver_id === user.id) {
                        setMessages(prev => {
                           // Prevent duplicates from any stray events
                           if (prev.find(m => m.id === msg.id)) return prev;
                           return [...prev, msg];
                        });
                   }
               })
               .subscribe();
        };

        init();
        return () => { 
            ignore = true; 
            if(channel) supabase.removeChannel(channel); 
        };
    }, [friendId]);

    const handleSend = async (content: string, type: 'text'|'image'|'audio' = 'text', mediaUrl?: string) => {
        if (!currentUser) return;

        // Optimistic UI Update with a unique temporary ID
        const tempId = `local_${Date.now()}`;
        const optimisticMsg: Message = {
            id: tempId,
            sender_id: currentUser.id,
            receiver_id: friendId,
            content,
            type,
            media_url: mediaUrl,
            created_at: new Date().toISOString()
        };
        setMessages(prev => [...prev, optimisticMsg]);

        try {
            const savedMessage = await api.sendMessage(currentUser.id, friendId, content, type, mediaUrl);
            // Replace the optimistic message with the real one from the server
            setMessages(prev => prev.map(m => m.id === tempId ? savedMessage : m));
        } catch (e) {
            console.error("Send failed", e);
            // On failure, remove the optimistic message to indicate it wasn't sent
            setMessages(prev => prev.filter(m => m.id !== tempId));
        }
    };

    const startCall = () => {
        if (!currentUser) return;
        const roomId = [currentUser.id, friendId].sort().join('-');
        navigate(`/call/${roomId}`);
    };

    return (
        <>
            <Lightbox isOpen={!!lightboxSrc} src={lightboxSrc || ''} onClose={() => setLightboxSrc(null)} />
            <motion.div 
              {...theme.motion.page}
              style={{ 
                display: 'flex', flexDirection: 'column', height: '100dvh', 
                background: theme.colors.surface1, width: '100%', maxWidth: theme.layout.maxWidth, margin: '0 auto', position: 'relative', overflow: 'hidden'
              }}
            >
                <ChatHeader title={friendProfile?.username || 'Chat'} onCall={startCall} />

                <div className="scrollbar-hide" style={{ flex: 1, overflowY: 'auto', padding: '0 24px 100px 24px', display: 'flex', flexDirection: 'column', gap: '12px' }}>
                    {messages.length === 0 && (
                       <div style={{ height: '100%', ...commonStyles.flexCenter, flexDirection: 'column', opacity: 0.3, gap: '16px' }}>
                          <div style={{ width: '40px', height: '40px', borderRadius: '50%', border: `1px solid ${theme.colors.text3}` }}></div>
                          <p style={{ fontSize: '12px', letterSpacing: '2px' }}>Start a conversation</p>
                       </div>
                    )}

                    {messages.map((msg) => (
                        <MessageBubble 
                            key={msg.id} 
                            msg={msg} 
                            isMe={msg.sender_id === currentUser?.id} 
                            onImageClick={(url) => setLightboxSrc(url)}
                        />
                    ))}
                    <div ref={messagesEndRef} style={{ height: '1px' }} />
                </div>

                <ChatInput onSend={handleSend} />
            </motion.div>
        </>
    );
};

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Microphone, MicrophoneSlash, PhoneDisconnect, VideoCamera, VideoCameraSlash, DesktopTower, Screencast, Users, ArrowsOut, WarningCircle, WifiHigh, WifiSlash } from '@phosphor-icons/react';
import { motion, AnimatePresence } from 'framer-motion';
import { theme, commonStyles } from '../../Theme';
import { api, supabase } from '../../services/supabaseClient';
import { CurrentUser } from '../../types';

interface Peer {
  id: string;
  connection: RTCPeerConnection;
  stream?: MediaStream;
  connectionState?: RTCIceConnectionState;
}

const ICE_SERVERS = {
  iceServers: [
    // Free, public STUN servers. More servers increase the chance of finding a connection path.
    { urls: 'stun:stun.l.google.com:19302' },
    { urls: 'stun:stun1.l.google.com:19302' },
    { urls: 'stun:stun2.l.google.com:19302' },
    { urls: 'stun:stun.global.max.com:3478' },
    { urls: 'stun:stun.mixvoip.com:3478' },
    { urls: 'stun:stun.nextcloud.com:443' },

    // --- PRODUCTION CRITICAL ---
    // The public TURN server below is provided for demonstration and may be unreliable or slow,
    // which is a common cause for connection issues like 'disconnected' or 'failed' states.
    // For a stable application, you MUST deploy your own TURN server (e.g., COTURN) or use a
    // paid service like Twilio or Xirsys.
    {
      urls: [
        'turn:openrelay.metered.ca:80',
        'turn:openrelay.metered.ca:443',
        'turn:openrelay.metered.ca:80?transport=tcp',
        'turn:openrelay.metered.ca:443?transport=tcp'
      ],
      username: 'openrelayproject',
      credential: 'openrelayproject'
    }
  ]
};

export const DirectCall: React.FC = () => {
  const { roomId } = useParams<{ roomId: string }>();
  const navigate = useNavigate();

  const [currentUser, setCurrentUser] = useState<CurrentUser | null>(null);
  const [peers, setPeers] = useState<Record<string, Peer>>({});
  const [isMuted, setIsMuted] = useState(false);
  const [isVideoEnabled, setIsVideoEnabled] = useState(false); 
  const [isScreenSharing, setIsScreenSharing] = useState(false);
  const [status, setStatus] = useState('Initializing...');
  const [fullScreenPeerId, setFullScreenPeerId] = useState<string | null>(null);
  const [connectionStatus, setConnectionStatus] = useState<RTCIceConnectionState>('new');

  // Refs
  const localStreamRef = useRef<MediaStream | null>(null);
  const peersRef = useRef<Record<string, Peer>>({});
  const userRef = useRef<CurrentUser | null>(null);
  const channelRef = useRef<any>(null);
  const localVideoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    // Pre-flight security and compatibility check
    if (window.location.protocol !== 'https:' && !['localhost', '1227.0.0.1'].includes(window.location.hostname)) {
        setStatus('Error: Secure connection (HTTPS) required.');
        setConnectionStatus('failed');
        return;
    }
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setStatus('Error: Media devices API not supported.');
        setConnectionStatus('failed');
        return;
    }
  }, []);

  const leaveCall = () => {
      // Send leave signal before cleaning up
      if (channelRef.current && userRef.current) {
          channelRef.current.send({
              type: 'broadcast',
              event: 'leave',
              payload: { userId: userRef.current.id }
          });
      }

      localStreamRef.current?.getTracks().forEach(t => t.stop());
      Object.values(peersRef.current).forEach((p: Peer) => p.connection.close());
      peersRef.current = {};
      setPeers({}); // Also clear React state
      if (channelRef.current) {
          supabase.removeChannel(channelRef.current);
          channelRef.current = null;
      }
  };

  useEffect(() => {
    let mounted = true;

    const init = async () => {
      if (!mounted || status.startsWith('Error:')) return;

      try {
        const user = await api.getCurrentUser();
        if(!mounted) return;
        setCurrentUser(user);
        userRef.current = user;

        setStatus('Requesting permissions...');
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });

        if (!mounted) {
            stream.getTracks().forEach(t => t.stop());
            return;
        }

        stream.getVideoTracks().forEach(t => t.enabled = false);

        localStreamRef.current = stream;
        if (localVideoRef.current) {
             localVideoRef.current.srcObject = stream;
             localVideoRef.current.muted = true;
        }

        setStatus('Joining channel...');

        const channel = supabase.channel(`call:${roomId}`, {
          config: { broadcast: { self: true } }
        });
        channelRef.current = channel;

        channel.on('broadcast', { event: 'join' }, ({ payload }: any) => {
            if (payload.userId !== user.id) {
                console.log(`User ${payload.userId} joined, initiating call...`);
                createPeer(payload.userId, true);
            }
        });

        channel.on('broadcast', { event: 'leave' }, ({ payload }: any) => {
            if (payload.userId !== userRef.current?.id) {
                setStatus('Peer has left the call.');

                // Clean up without broadcasting back
                localStreamRef.current?.getTracks().forEach(t => t.stop());
                Object.values(peersRef.current).forEach((p: Peer) => p.connection.close());
                peersRef.current = {};
                setPeers({});
                if (channelRef.current) {
                    supabase.removeChannel(channelRef.current);
                    channelRef.current = null;
                }

                setTimeout(() => navigate(-1), 2000);
            }
        });

        channel.on('broadcast', { event: 'signal' }, async ({ payload }: any) => {
            if (payload.to !== user.id) return;

            const { from, type, data } = payload;
            let peer = peersRef.current[from];

            if (!peer) {
                const newPeer = createPeer(from, false);
                if (!newPeer) return; // Peer creation failed (call is busy)
                peer = newPeer;
            }

            try {
                if (type === 'offer') {
                    await peer.connection.setRemoteDescription(new RTCSessionDescription(data));
                    const answer = await peer.connection.createAnswer();
                    await peer.connection.setLocalDescription(answer);
                    channel.send({
                        type: 'broadcast', event: 'signal',
                        payload: { to: from, from: user.id, type: 'answer', data: answer }
                    });
                } else if (type === 'answer') {
                    await peer.connection.setRemoteDescription(new RTCSessionDescription(data));
                } else if (type === 'candidate') {
                    await peer.connection.addIceCandidate(new RTCIceCandidate(data));
                }
            } catch (e) { console.error("Signaling error", e); }
        });

        channel.subscribe(async (subStatus: string) => {
            if (subStatus === 'SUBSCRIBED') {
                setStatus('Broadcasting presence...');
                const broadcastStatus = await channel.send({
                    type: 'broadcast', event: 'join',
                    payload: { userId: user.id }
                });

                if (broadcastStatus === 'ok') {
                    setStatus('Waiting for peer...');
                } else {
                    console.error('Broadcast failed with status:', broadcastStatus);
                    setStatus('Error: Connection failed.');
                    setConnectionStatus('failed');
                }
            } else if (subStatus === 'TIMED_OUT' || subStatus === 'CHANNEL_ERROR') {
                console.error('Supabase channel subscription failed:', subStatus);
                setStatus('Error: Real-time connection failed.');
                setConnectionStatus('failed');
            }
        });

      } catch (e: any) {
        console.error(e);
        const errorMsg = e.name === 'NotAllowedError' ? 'Permissions denied.' : 'No media devices.';
        setStatus(`Error: ${errorMsg}`);
        setConnectionStatus('failed');
      }
    };

    init();

    return () => {
        mounted = false;
        leaveCall();
    };
  }, [roomId]);

  const createPeer = (targetId: string, initiator: boolean): Peer | null => {
      // Enforce 1-on-1 call by rejecting new connections if one already exists.
      const existingPeers = Object.keys(peersRef.current);
      if (existingPeers.length > 0 && !peersRef.current[targetId]) {
          console.warn(`[DirectCall] Rejecting incoming connection from ${targetId}. A call is already in progress with ${existingPeers[0]}.`);
          return null; // Return null to indicate failure.
      }

      if (peersRef.current[targetId]) return peersRef.current[targetId];

      const pc = new RTCPeerConnection(ICE_SERVERS);

      localStreamRef.current?.getTracks().forEach(track => {
          pc.addTrack(track, localStreamRef.current!);
      });

      pc.ontrack = (event) => {
          console.log(`Received media stream from ${targetId}`);
          setPeers(prev => ({
              ...prev,
              [targetId]: { ...prev[targetId], stream: event.streams[0] }
          }));
      };

      pc.oniceconnectionstatechange = () => {
          console.log(`ICE state for ${targetId}: ${pc.iceConnectionState}`);
          setConnectionStatus(pc.iceConnectionState); // Update global status for UI

          switch (pc.iceConnectionState) {
              case 'checking':
                  setStatus('Establishing connection...');
                  break;
              case 'connected':
              case 'completed':
                  setStatus('Media connected.');
                  break;
              case 'disconnected':
                  setStatus('Connection lost. Reconnecting...');
                  break;
              case 'failed':
                  setStatus('Connection failed. Network may be too restrictive.');
                  break;
              case 'closed':
                  setStatus('Call ended.');
                  break;
          }

          setPeers(prev => {
              if (prev[targetId]) {
                  return { ...prev, [targetId]: { ...prev[targetId], connectionState: pc.iceConnectionState }};
              }
              return prev;
          });
      };

      pc.onicecandidate = (event) => {
          if (event.candidate && channelRef.current) {
              channelRef.current.send({
                  type: 'broadcast', event: 'signal',
                  payload: { to: targetId, from: userRef.current?.id, type: 'candidate', data: event.candidate }
              });
          }
      };

      const peer: Peer = { id: targetId, connection: pc, connectionState: 'new' };
      peersRef.current[targetId] = peer;
      setPeers(prev => ({ ...prev, [targetId]: peer }));

      if (initiator) {
          pc.createOffer()
            .then(offer => pc.setLocalDescription(offer))
            .then(() => {
                channelRef.current?.send({
                    type: 'broadcast', event: 'signal',
                    payload: { to: targetId, from: userRef.current?.id, type: 'offer', data: pc.localDescription }
                });
            })
            .catch(e => console.error("Offer creation failed", e));
      }

      return peer;
  };

  const toggleMute = () => {
      if (localStreamRef.current) {
          const track = localStreamRef.current.getAudioTracks()[0];
          if (track) {
              track.enabled = !track.enabled;
              setIsMuted(!track.enabled);
          }
      }
  };

  const toggleVideo = () => {
      if (localStreamRef.current) {
          const track = localStreamRef.current.getVideoTracks()[0];
          if (track) {
              track.enabled = !track.enabled;
              setIsVideoEnabled(track.enabled);
              if (isScreenSharing && track.enabled) setIsScreenSharing(false);
          }
      }
  };

  const toggleScreenShare = async () => {
    const replaceVideoTrack = (newTrack: MediaStreamTrack) => {
        if (localStreamRef.current) {
            const oldTrack = localStreamRef.current.getVideoTracks()[0];
            if (oldTrack) {
                oldTrack.stop();
                localStreamRef.current.removeTrack(oldTrack);
            }
            localStreamRef.current.addTrack(newTrack);
            // Fix: Explicitly type the 'p' parameter to 'Peer' to fix type inference from Object.values.
            Object.values(peersRef.current).forEach((p: Peer) => {
                const sender = p.connection.getSenders().find(s => s.track?.kind === 'video');
                sender?.replaceTrack(newTrack);
            });
        }
    };

    if (isScreenSharing) {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ video: true });
            const newTrack = stream.getVideoTracks()[0];
            replaceVideoTrack(newTrack);
            setIsScreenSharing(false);
        } catch (e) { console.error("Cam failed", e); }
    } else {
        try {
            const stream = await navigator.mediaDevices.getDisplayMedia({ video: true });
            const newTrack = stream.getVideoTracks()[0];
            newTrack.onended = () => toggleScreenShare();
            replaceVideoTrack(newTrack);
            setIsScreenSharing(true);
            setIsVideoEnabled(true);
        } catch (e) { console.error("Screen share failed", e); }
    }
  };

  const isError = status.startsWith('Error:');

  const getStatusIcon = () => {
      if (isError || connectionStatus === 'failed') return <WifiSlash weight="fill" color={theme.colors.danger} />;
      if (connectionStatus === 'connected' || connectionStatus === 'completed') return <WifiHigh weight="fill" color="#22c55e" />;
      return <WarningCircle weight="fill" />;
  };

  return (
    <motion.div 
      {...theme.motion.page}
      style={{ 
        ...commonStyles.pageContainer, background: '#000', 
        position: 'fixed', inset: 0, zIndex: 2000,
        flexDirection: 'column', justifyContent: 'space-between', overflow: 'hidden'
      }}
    >
        <AnimatePresence>
            {fullScreenPeerId && (
                <motion.div
                    initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                    style={{ position: 'absolute', inset: 0, zIndex: 3000, background: 'black', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                    onClick={() => setFullScreenPeerId(null)}
                >
                    {fullScreenPeerId === 'local' ? (
                        <video 
                            ref={(el) => { if(el && localStreamRef.current) el.srcObject = localStreamRef.current; }}
                            autoPlay muted playsInline style={{ width: '100%', height: '100%', objectFit: 'contain' }} 
                        />
                    ) : (
                         peers[fullScreenPeerId] && <FullScreenVideo peer={peers[fullScreenPeerId]} />
                    )}
                    <button style={{ position: 'absolute', top: 24, right: 24, background: 'rgba(0,0,0,0.5)', borderRadius: '50%', border: 'none', color: 'white', padding: '12px' }}>
                        <ArrowsOut size={24} />
                    </button>
                </motion.div>
            )}
        </AnimatePresence>

        <div style={{ padding: '32px', textAlign: 'center', zIndex: 10, display: 'flex', justifyContent: 'center' }}>
            <div style={{ 
                background: isError ? 'rgba(220, 38, 38, 0.1)' : 'rgba(255,255,255,0.05)', 
                color: isError ? theme.colors.danger : theme.colors.text3,
                border: `1px solid ${isError ? theme.colors.danger : 'rgba(255,255,255,0.1)'}`,
                padding: '8px 16px', borderRadius: theme.radius.full,
                display: 'flex', alignItems: 'center', gap: '8px',
                fontSize: '12px', backdropFilter: 'blur(10px)',
            }}>
                {getStatusIcon()}
                {status} <span style={{ opacity: 0.5 }}>({connectionStatus})</span>
            </div>
        </div>

        <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '24px', flexWrap: 'wrap', padding: '24px', overflowY: 'auto' }}>
            <div 
